<?php
session_start();
if (empty($_SESSION['placed_orders'])) { header('Location: view_orders.php'); exit; }
$orders = json_decode(file_get_contents('../data/order.json'), true);
$last_order = end($orders);
if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['confirm_payment'])) {
    $method = $_POST['payment_method'] ?? 'gcash';
    $orders[count($orders)-1]['payment_method'] = strtoupper($method);
    $orders[count($orders)-1]['status'] = 'Preparing';
    file_put_contents('data/orders.json', json_encode($orders, JSON_PRETTY_PRINT));
    header('Location: order_status.php'); exit;
}
?>
